/**
 * API Route: Public Contact Sales Button by Language
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export const dynamic = 'force-dynamic';
export const revalidate = 0;

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const language = searchParams.get('language') || 'en';

    console.log('Contact Sales API: Fetching button for language:', language);

    // دریافت دکمه فعال برای این زبان
    const button = await prisma.contactSalesButton.findFirst({
      where: {
        language,
        isActive: true,
        show: true
      }
    });

    if (!button) {
      console.log('Contact Sales API: No active button found for', language);
      // Fallback به زبان پیشفرض
      const defaultButton = await prisma.contactSalesButton.findFirst({
        where: {
          language: 'en',
          isActive: true,
          show: true
        }
      });

      if (!defaultButton) {
        console.log('Contact Sales API: No default button found either');
        return NextResponse.json({ 
          success: false,
          button: null 
        });
      }

      return NextResponse.json({
        success: true,
        button: {
          ...defaultButton,
          style: defaultButton.style ? JSON.parse(defaultButton.style) : null
        },
        fallback: true
      });
    }

    console.log('Contact Sales API: Button found:', button.id);

    return NextResponse.json({
      success: true,
      button: {
        ...button,
        style: button.style ? JSON.parse(button.style) : null
      }
    });

  } catch (error) {
    console.error('Contact Sales API error:', error);
    return NextResponse.json({ 
      success: false,
      error: 'Failed to fetch button',
      button: null 
    }, { status: 500 });
  }
}
